import threading
import time
import random

class ATM:
    def __init__(self, id, initial_balance):
        self.id = id
        self.balance = initial_balance
        self.lock = threading.Lock()

    def deposit(self, amount):
        with self.lock:
            self.balance += amount
            print(f"ATM {self.id}: Deposited {amount}. New balance: {self.balance}")

    def withdraw(self, amount):
        with self.lock:
            if amount <= self.balance:
                self.balance -= amount
                print(f"ATM {self.id}: Withdrawn {amount}. New balance: {self.balance}")
                return amount
            else:
                print(f"ATM {self.id}: Withdrawal of {amount} failed. Insufficient funds.")
                return 0

class Bank:
    def __init__(self):
        self.atms = {}
        self.lock = threading.Lock()

    def add_atm(self, atm):
        with self.lock:
            self.atms[atm.id] = atm

    def get_atm(self, atm_id):
        with self.lock:
            return self.atms.get(atm_id)

def atm_operations(atm):
    for _ in range(5):
        operation = random.choice(['deposit', 'withdraw'])
        amount = random.randint(1, 100)
        if operation == 'deposit':
            atm.deposit(amount)
        else:
            atm.withdraw(amount)
        time.sleep(random.uniform(0.1, 0.5))

def main():
    bank = Bank()
    atms = [ATM(i, 1000) for i in range(5)]

    for atm in atms:
        bank.add_atm(atm)

    threads = []
    for atm in atms:
        thread = threading.Thread(target=atm_operations, args=(atm,))
        threads.append(thread)
        thread.start()

    for thread in threads:
        thread.join()

if __name__ == "__main__":
    main()

