class ATMRestraint:
    def __init__(self):
        self.active_transactions = {}
        self.failed_transactions = []
        self.locked_atms = set()

    def start_transaction(self, atm_id, transaction_id):
        if atm_id in self.locked_atms:
            return "ATM is currently locked. Transaction cannot be processed."
        if transaction_id in self.active_transactions:
            return "Transaction is already in progress."

        self.active_transactions[transaction_id] = atm_id
        return "Transaction started."

    def complete_transaction(self, transaction_id):
        if transaction_id in self.active_transactions:
            atm_id = self.active_transactions.pop(transaction_id)
            return f"Transaction {transaction_id} completed at ATM {atm_id}."
        else:
            return "Transaction not found."

    def fail_transaction(self, transaction_id):
        if transaction_id in self.active_transactions:
            atm_id = self.active_transactions.pop(transaction_id)
            self.failed_transactions.append(transaction_id)
            self.locked_atms.add(atm_id)
            return f"Transaction {transaction_id} failed at ATM {atm_id}. ATM is now locked."
        else:
            return "Transaction not found."

    def unlock_atm(self, atm_id):
        if atm_id in self.locked_atms:
            self.locked_atms.remove(atm_id)
            return f"ATM {atm_id} is now unlocked."
        else:
            return "ATM is not locked."

    def get_status(self):
        return {
            "active_transactions": self.active_transactions,
            "failed_transactions": self.failed_transactions,
            "locked_atms": self.locked_atms
        }

